export function haversineKm(
  lat1: number, lng1: number,
  lat2: number, lng2: number
): number {
  const R = 6371;  // Earth radius in km
  const toRad = (deg: number) => (deg * Math.PI) / 180;

  const dLat = toRad(lat2 - lat1);
  const dLng = toRad(lng2 - lng1);

  const a =
    Math.sin(dLat / 2) ** 2 +
    Math.cos(toRad(lat1)) *
    Math.cos(toRad(lat2)) *
    Math.sin(dLng / 2) ** 2;

  const km = R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
  return Math.round(km * 10) / 10;  // round to 1 decimal
}

// Levenshtein edit distance — counts minimum character changes
// between two strings (insert, delete, or substitute one char).
function editDistance(a: string, b: string): number {
  const m = a.length, n = b.length;
  const prev = Array.from({ length: n + 1 }, (_, j) => j);
  const curr = new Array<number>(n + 1);
  for (let i = 1; i <= m; i++) {
    curr[0] = i;
    for (let j = 1; j <= n; j++) {
      curr[j] = a[i-1] === b[j-1]
        ? prev[j-1]
        : 1 + Math.min(prev[j], curr[j-1], prev[j-1]);
    }
    prev.splice(0, n+1, ...curr);
  }
  return prev[n];
}

// Returns true if token fuzzy-matches anywhere in text.
// Allowed edits: 1 for tokens >=4 chars, 2 for >=6 chars.
export function fuzzyContains(text: string, token: string): boolean {
  const t = token.toLowerCase(), s = text.toLowerCase();
  if (s.includes(t)) return true;  // exact substring wins
  const maxDist = t.length >= 6 ? 2 : t.length >= 4 ? 1 : 0;
  if (maxDist === 0) return false;
  return s.split(/\s+/).some(w => editDistance(t, w) <= maxDist);
}
